import openpyxl
from datetime import datetime

wb = openpyxl.load_workbook('input.xlsx')
ws = wb['Sheet1']

# Build holiday lookup from columns H/I/J
holidays = {}
for row in range(2, ws.max_row + 1):
    date_val = ws.cell(row=row, column=9).value  # Column I
    type_val = ws.cell(row=row, column=10).value  # Column J
    if date_val and type_val:
        if isinstance(date_val, datetime):
            holidays[date_val.date()] = type_val

# Fill E2:E75
day_abbr = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
for row in range(2, 76):
    date_val = ws.cell(row=row, column=1).value
    if date_val:
        d = date_val.date() if isinstance(date_val, datetime) else date_val
        if d in holidays:
            ws.cell(row=row, column=5).value = holidays[d]
        else:
            ws.cell(row=row, column=5).value = day_abbr[d.weekday()]

wb.save('output.xlsx')
print("Done")
EOF
